import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const AdGrid = ({ pageNumber = 1 }) => {
  const [squares, setSquares] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [shuffleCountdown, setShuffleCountdown] = useState(7200); // 2 hours in seconds
  const navigate = useNavigate();

  // Calculate square numbers for this page
  const startSquare = (pageNumber - 1) * 200 + 1;
  const endSquare = pageNumber * 200;

  // Shuffle countdown timer
  useEffect(() => {
    const timer = setInterval(() => {
      setShuffleCountdown(prev => {
        if (prev <= 1) {
          shuffleSquares();
          return 7200; // Reset to 2 hours
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  // Format time for display
  const formatTime = (seconds) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    return `${hours}h ${minutes}m`;
  };

  // Shuffle squares function
  const shuffleSquares = () => {
    setSquares(prevSquares => {
      const occupied = prevSquares.filter(sq => !sq.isAvailable);
      const available = prevSquares.filter(sq => sq.isAvailable);
      
      // Shuffle occupied squares
      const shuffledOccupied = [...occupied].sort(() => Math.random() - 0.5);
      
      // Combine and maintain order
      const allSquares = [...shuffledOccupied, ...available];
      
      console.log(`🔄 Shuffled ${occupied.length} occupied squares on Page ${pageNumber}`);
      return allSquares;
    });
  };

  useEffect(() => {
    const initializeSquares = () => {
      setIsLoading(true);
      
      // Create mock purchases for testing all pages
      const createMockPurchases = () => {
        const mockPurchases = {};
        
        for (let page = 1; page <= 10; page++) {
          const pageStart = (page - 1) * 200 + 1;
          
          // Mark a few squares as occupied on each page
          for (let i = 0; i < 8; i++) {
            const squareNum = pageStart + (i * 25);
            mockPurchases[squareNum] = {
              status: 'active',
              businessName: `Business ${squareNum}`,
              logoData: '/logo.PNG',
              adText: `Special Deal ${squareNum}`,
              dealLink: 'https://example.com',
              endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
            };
          }
        }
        return mockPurchases;
      };

      // Load or create purchases
      let purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
      
      if (Object.keys(purchases).length === 0) {
        purchases = createMockPurchases();
        localStorage.setItem('squarePurchases', JSON.stringify(purchases));
      }

      // Create ALL 200 squares for current page
      const initialSquares = Array.from({ length: 200 }, (_, i) => {
        const squareNumber = startSquare + i;
        const purchase = purchases[squareNumber];
        
        if (purchase && purchase.status === 'active') {
          const endDate = new Date(purchase.endDate);
          const today = new Date();
          
          if (today < endDate) {
            return {
              id: squareNumber,
              isAvailable: false,
              businessName: purchase.businessName,
              logoData: purchase.logoData,
              adText: purchase.adText,
              dealLink: purchase.dealLink,
              endDate: purchase.endDate
            };
          }
        }
        
        return {
          id: squareNumber,
          isAvailable: true,
          price: '£1/day'
        };
      });

      // Initial shuffle for visual appeal
      const shuffledSquares = [...initialSquares].sort(() => Math.random() - 0.5);
      
      setSquares(shuffledSquares);
      setIsLoading(false);
      
      console.log(`Page ${pageNumber}: Loaded ${shuffledSquares.length} squares`);
    };

    initializeSquares();
  }, [pageNumber, startSquare]);

  const handleSquareClick = (square) => {
    if (square.isAvailable) {
      navigate('/purchase', { 
        state: { 
          squareNumber: square.id,
          pageNumber: pageNumber 
        } 
      });
    } else {
      window.open(square.dealLink, '_blank');
    }
  };

  // Loading state
  if (isLoading) {
    return (
      <div className="grid-container">
        <div className="page-info">
          <h3>Page {pageNumber} - Loading Squares...</h3>
        </div>
        <div className="squares-grid loading-squares">
          {Array.from({ length: 200 }).map((_, i) => (
            <div key={i} className="loading-square"></div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="grid-container">
      <div className="page-info">
        <h3>Page {pageNumber} - Squares {startSquare} to {endSquare}</h3>
        <p>
          {squares.filter(square => !square.isAvailable).length}/200 squares occupied
        </p>
        <div className="shuffle-indicator">
          🔄 Auto-shuffle in: {formatTime(shuffleCountdown)}
        </div>
      </div>
      
      <div className="squares-grid">
        {squares.map(square => (
          <div
            key={square.id}
            className={`square ${square.isAvailable ? '' : 'occupied'}`}
            onClick={() => handleSquareClick(square)}
            title={!square.isAvailable ? 
              `${square.businessName}\nClick to visit deal` : 
              'Click to purchase this square\n£1 per day - Affordable advertising'
            }
          >
            {square.isAvailable ? (
              <>
                <div className="square-text">BUY THIS SQUARE</div>
                <div className="square-price">{square.price}</div>
                <div className="square-number">#{square.id}</div>
              </>
            ) : (
              <img 
                src={square.logoData || '/logo.PNG'} 
                alt={square.businessName} 
                className="occupied-logo" 
              />
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdGrid;
